def process_graph(graph_data):
    # Create a copy of the graph to avoid modifying the input graph
    graph_copy = graph_data.copy()

    # Find the EK_AGG_BLOCK node named 'ju1.a2.m3'
    ju1_a2_m3 = None
    for node in graph_copy.nodes():
        if graph_copy.nodes[node].get('name') == 'ju1.a2.m3' and 'EK_AGG_BLOCK' in graph_copy.nodes[node].get('type', []):
            ju1_a2_m3 = node
            break

    if not ju1_a2_m3:
        return {"type": "text", "data": "Node ju1.a2.m3 not found", "updated_graph": nx.readwrite.json_graph.node_link_data(graph_copy)}

    # Get all EK_PACKET_SWITCH nodes contained in this EK_AGG_BLOCK node
    switches = []
    for neighbor in nx.descendants(graph_copy, ju1_a2_m3):
        if 'EK_PACKET_SWITCH' in graph_copy.nodes[neighbor].get('type', []):
            switches.append(neighbor)

    # For each EK_PACKET_SWITCH node, get the sum of physical_capacity_bps for its EK_PORT nodes
    switch_capacities = []
    for switch in switches:
        total_capacity = 0
        for neighbor in nx.descendants(graph_copy, switch):
            if 'EK_PORT' in graph_copy.nodes[neighbor].get('type', []):
                total_capacity += graph_copy.nodes[neighbor].get('physical_capacity_bps', 0)
        switch_capacities.append((str(switch), total_capacity))

    # Sort the switches by total physical capacity in descending order
    switch_capacities.sort(key=lambda x: x[1], reverse=True)

    # Return the sorted list, the node name will be used with the tuple
    return_object = {
        "type": "list",
        "data": [(name, capacity) for name, capacity in switch_capacities],
        "updated_graph": nx.readwrite.json_graph.node_link_data(graph_copy)
    }

    return return_object

